package main

import "fmt"

func main() {
    // ---- Basic printing ----
    fmt.Println("=== fmt and Formatting ===")

    // ---- Println ----
    fmt.Println("Hello, World!")
    fmt.Println("Multiple", "values", "with", "Println")

    // ---- Printf (formatted printing) ----
    name := "Hero"
    health := 100
    attack := 20.5

    fmt.Printf("Name: %s\n", name)
    fmt.Printf("Health: %d\n", health)
    fmt.Printf("Attack: %.2f\n", attack)

    // ---- Format specifiers ----
    // %v = default format
    // %+v = with field names
    // %#v = Go-syntax representation
    // %T = type

    type Player struct {
        Name   string
        Health int
    }

    p := Player{Name: "Hero", Health: 100}

    fmt.Printf("Default: %v\n", p)
    fmt.Printf("With fields: %+v\n", p)
    fmt.Printf("Go-syntax: %#v\n", p)
    fmt.Printf("Type: %T\n", p)

    // ---- Print to string ----
    s := fmt.Sprintf("Name: %s, Health: %d", name, health)
    fmt.Println("Sprintf:", s)

    // ---- Print to error ----
    err := fmt.Errorf("error: %s not found", name)
    fmt.Println("Error:", err)

    // ---- Formatting numbers ----
    num := 12345.6789

    fmt.Printf("Default: %f\n", num)
    fmt.Printf("Two decimals: %.2f\n", num)
    fmt.Printf("Scientific: %e\n", num)
    fmt.Printf("Commas: %,.2f\n", num)

    // ---- Formatting integers ----
    n := 255

    fmt.Printf("Decimal: %d\n", n)
    fmt.Printf("Binary: %b\n", n)
    fmt.Printf("Octal: %o\n", n)
    fmt.Printf("Hex: %x\n", n)
    fmt.Printf("Upper Hex: %X\n", n)

    // ---- Formatting strings ----
    str := "Hello, World!"

    fmt.Printf("String: %s\n", str)
    fmt.Printf("Quoted: %q\n", str)
    fmt.Printf("Width: %20s\n", str)
    fmt.Printf("Left aligned: %-20s\n", str)

    // ---- Formatting structs ----
    fmt.Printf("Struct: %+v\n", p)

    // ---- Fprint (write to file or writer) ----
    // fmt.Fprint(writer, "Hello")

    // ---- Scan ----
    // var input string
    // fmt.Scanln(&input)
    // fmt.Printf("You entered: %s\n", input)
}

